import { QuoteStoreService } from '../../services/quote-store.service';

const TVA_RATE = 19;

@Component({
  selector: 'app-quote-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterModule],
  templateUrl: './quote-form.component.html',
  styleUrls: ['./quote-form.component.css']
})
export class QuoteFormComponent implements OnInit, OnDestroy {
  private readonly destroy$ = new Subject<void>();

  form = this.fb.group({
    numero: ['', Validators.required],
    date: ['', Validators.required],
    client: this.fb.group({
      nom: ['', Validators.required],
      adresse: ['', Validators.required],
      tel: [''],
      mf: [''],
      email: ['']
    }),
    lignes: this.fb.array([]),
    remiseType: ['montant' as QuoteRemiseType],
    remiseValue: [0],
    notes: [''],
    conditions: ['']
  });

  totals: QuoteTotals = {
    totalHT: 0,
    remise: 0,
    totalHTApresRemise: 0,
    fodec: 0,
    totalHorsTVA: 0,
    tva: 0,
    totalTTC: 0
  };

  isEdit = false;
  numeroConflict = false;

  private currentId: string | null = null;

  constructor(
    private fb: FormBuilder,
    private store: QuoteStoreService,
    public calc: QuoteCalcService,
    private route: ActivatedRoute,
    private router: Router
  ) {}

  get lignes(): FormArray {
    return this.form.get('lignes') as FormArray;
  }

  async ngOnInit(): Promise<void> {
    await this.store.load();

    const id = this.route.snapshot.paramMap.get('id');

    if (id) {
      this.isEdit = true;
      const quote = await this.store.getById(id);
      if (!quote) {
        this.router.navigate(['/quotes']);
        return;
      }

      this.currentId = quote.id;

      this.form.patchValue({
        numero: quote.numero,
        date: quote.date,
        client: quote.client,
        remiseType: quote.remiseType ?? 'montant',
        remiseValue: quote.remiseValue ?? 0,
        notes: quote.notes ?? '',
        conditions: quote.conditions ?? ''
      });

      this.setLines(quote.lignes ?? []);
    } else {
      this.isEdit = false;
      this.currentId = this.ensureCurrentId();

      const numero = await this.store.getNextQuoteNumber();
      this.form.patchValue({
        numero,
        date: new Date().toISOString().slice(0, 10),
        remiseType: 'montant',
        remiseValue: 0
      });

      this.addLine();
    }

    this.form.valueChanges
      .pipe(startWith(this.form.getRawValue()), takeUntil(this.destroy$))
      .subscribe(() => this.updateTotals());

    this.updateTotals();
  }

  ngOnDestroy(): void {
    this.destroy$.next();
    this.destroy$.complete();
  }

  addLine(): void {
    this.lignes.push(this.createLine());
  }

  removeLine(index: number): void {
    if (this.lignes.length <= 1) return;
    this.lignes.removeAt(index);
  }

  lineHT(index: number): number {
    const line = this.normalizeLine(this.lignes.at(index).value as InvoiceLine);
    return this.calc.lineHT(line);
  }

  async save(goToPreview: boolean): Promise<void> {
    this.numeroConflict = false;

    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }

    const quote = this.buildQuote();

    const unique = await this.store.isNumeroUnique(quote.numero, quote.id);
    if (!unique) {
      this.numeroConflict = true;
      return;
    }

    await this.store.save(quote);

    if (goToPreview) {
      this.router.navigate(['/quotes', quote.id, 'preview']);
    } else {
      this.router.navigate(['/quotes']);
    }
  }

  cancel(): void {
    this.router.navigate(['/quotes']);
  }

  private updateTotals(): void {
    const quote = this.buildQuote();
    this.totals = this.calc.totals(quote);
  }

  private setLines(lines: InvoiceLine[]): void {
    this.lignes.clear();
    lines.forEach((line) => this.lignes.push(this.createLine(line)));
    if (lines.length === 0) this.addLine();
  }

  private createLine(line?: InvoiceLine): ReturnType<FormBuilder['group']> {
    return this.fb.group({
      id: [line?.id ?? this.createId()],
      designation: [line?.designation ?? '', Validators.required],
      unite: [line?.unite ?? '', Validators.required],
      quantite: [line?.quantite ?? 0, [Validators.required, Validators.min(0)]],
      prixUnitaire: [line?.prixUnitaire ?? 0, [Validators.required, Validators.min(0)]],
      tvaRate: [TVA_RATE]
    });
  }

  private buildQuote(): Quote {
    const raw = this.form.getRawValue();

    return {
      id: this.ensureCurrentId(),
      numero: (raw.numero ?? '').trim(),
      date: (raw.date ?? new Date().toISOString().slice(0, 10)).trim(),
      client: {
        nom: raw.client?.nom ?? '',
        adresse: raw.client?.adresse ?? '',
        tel: raw.client?.tel ?? '',
        mf: raw.client?.mf ?? '',
        email: raw.client?.email ?? ''
      },
      lignes: ((raw.lignes ?? []) as InvoiceLine[]).map((l) => this.normalizeLine(l)),
      remiseType: raw.remiseType ?? 'montant',
      remiseValue: Number(raw.remiseValue) || 0,
      notes: raw.notes ?? '',
      conditions: raw.conditions ?? ''
    };
  }

  private normalizeLine(line: InvoiceLine): InvoiceLine {
    return {
      ...line,
      quantite: Number(line.quantite) || 0,
      prixUnitaire: Number(line.prixUnitaire) || 0,
      tvaRate: TVA_RATE
    };
  }

  private ensureCurrentId(): string {
    if (!this.currentId) {
      this.currentId = this.createId();
    }

    return this.currentId;
  }

  private createId(): string {
    return globalThis.crypto?.randomUUID?.() ??
      `quote_${Date.now()}_${Math.random().toString(16).slice(2)}`;
  }
}
<section class="form-header">
  <div>
    <h1>{{ isEdit ? 'Modifier le devis' : 'Nouveau devis' }}</h1>
    <p>Les montants sont recalcul&eacute;s en temps r&eacute;el.</p>
  </div>
  <div class="form-header-actions">
    <a class="btn ghost" routerLink="/quotes">Retour liste</a>
  </div>
</section>

<form class="form-grid" [formGroup]="form" (ngSubmit)="save(false)">
  <section class="card">
    <h2>Informations devis</h2>
    <div class="grid-3">
      <label class="field">
        <span>Num&eacute;ro</span>
        <input class="input" formControlName="numero" type="text">
        <span class="error" *ngIf="numeroConflict">Ce num&eacute;ro existe d&eacute;j&agrave;.</span>
      </label>

      <label class="field">
        <span>Date</span>
        <input class="input" formControlName="date" type="date">
      </label>

      <div class="field">
        <span>Statut</span>
        <div class="tag">{{ isEdit ? 'Brouillon' : 'Nouveau' }}</div>
      </div>
    </div>
  </section>

  <section class="card">
    <h2>Client</h2>
    <div formGroupName="client" class="grid-2">
      <label class="field">
        <span>Nom</span>
        <input class="input" formControlName="nom" type="text">
      </label>

      <label class="field">
        <span>T&eacute;l&eacute;phone</span>
        <input class="input" formControlName="tel" type="text">
      </label>

      <label class="field">
        <span>Adresse</span>
        <textarea class="input" formControlName="adresse" rows="3"></textarea>
      </label>

      <div class="stack">
        <label class="field">
          <span>MF</span>
          <input class="input" formControlName="mf" type="text">
        </label>
        <label class="field">
          <span>Email</span>
          <input class="input" formControlName="email" type="email">
        </label>
      </div>
    </div>
  </section>

  <section class="card">
    <div class="section-head">
      <h2>Lignes produits</h2>
      <button type="button" class="btn outline" (click)="addLine()">Ajouter ligne</button>
    </div>

    <div class="lines" formArrayName="lignes">
      <div class="line-row line-head">
        <div>D&eacute;signation</div>
        <div>Unit&eacute;</div>
        <div>Qt&eacute;</div>
        <div>PU</div>
        <div>HT</div>
        <div></div>
      </div>

      <div
        class="line-row"
        *ngFor="let line of lignes.controls; let i = index"
        [formGroupName]="i"
      >
        <input class="input" formControlName="designation" placeholder="Profil&eacute; aluminium 6063">
        <input class="input" formControlName="unite" placeholder="m">
        <input class="input" formControlName="quantite" type="number" min="0" step="0.01">
        <input class="input" formControlName="prixUnitaire" type="number" min="0" step="0.01">

        <div class="amount">{{ lineHT(i) | number:'1.2-2' }}</div>

        <button type="button" class="btn danger" (click)="removeLine(i)">Supprimer</button>
      </div>
    </div>
  </section>

  <section class="card">
    <h2>Remise</h2>
    <div class="grid-3">
      <label class="field">
        <span>Type</span>
        <select class="input" formControlName="remiseType">
          <option value="montant">Montant</option>
          <option value="pourcentage">Pourcentage</option>
        </select>
      </label>

      <label class="field">
        <span>Valeur</span>
        <input class="input" type="number" min="0" step="0.01" formControlName="remiseValue">
      </label>
    </div>
  </section>

  <section class="card">
    <h2>Notes &amp; Conditions</h2>
    <div class="grid-2">
      <label class="field">
        <span>Notes</span>
        <textarea class="input" formControlName="notes" rows="4"></textarea>
      </label>
      <label class="field">
        <span>Conditions</span>
        <textarea class="input" formControlName="conditions" rows="4"></textarea>
      </label>
    </div>
  </section>

  <!-- ✅ TOTAUX DEVIS (HT + remise seulement) -->
  <section class="card totals">
    <h2>Totaux</h2>
    <div class="totals-grid">
      <div>
        <span>Total Hors taxes</span>
        <strong>{{ totals.totalHT | number:'1.2-2' }} DT</strong>
      </div>

      <div *ngIf="totals.remise > 0">
        <span>Remise</span>
        <strong>- {{ totals.remise | number:'1.2-2' }} DT</strong>
      </div>

      <div>
        <span>Total Net HT</span>
        <strong class="accent">{{ totals.totalHTApresRemise | number:'1.2-2' }} DT</strong>
      </div>
    </div>
  </section>

  <div class="form-actions">
    <button class="btn ghost" type="button" (click)="cancel()">Annuler</button>
    <button class="btn outline" type="submit">Enregistrer</button>
    <button class="btn primary" type="button" (click)="save(true)">Enregistrer &amp; Aper&ccedil;u</button>
  </div>
</form>
